import json, os
try:
    with open('/output/previous_run.json') as f:
        prev = json.load(f)
except FileNotFoundError:
    prev = {}
msg = prev.get('message')
if msg:
    summary = f"Previous run said: {msg!r}"
else:
    summary = 'Previous run said nothing (first run, predecessor failed, or no message was set).'
with open('/output/result.json', 'w') as f:
    json.dump({'summary': summary, 'previousMessage': msg}, f)
print(summary)
